steps.query:
query ListOrganizations($first: Int) {
  orgs(first: $first) {
    id
    name
    description
    phone
    website
    level
    createdAt
  }
}

query GetOrganization($id: ID!) {
  org(where: { id: $id }) {
    id
    name
    description
    phone
    website
    domain
    level
    createdAt
    updatedAt
    campaignOrders(first: 5) {
      id
      name
      status
    }
  }
}
